// Fetch country data from countries.json and process the data
fetch('countries.json')
  .then((response) => {
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    return response.json();
  })
  .then((countries) => {
    // Do something with the countries data, e.g., print a list of country names
