            .frame(width: 100, height: 100)
            .position(x: 100, y: 100)
            .focusable()
            .onAppear { UIApplication.shared.isIdleTimerDisabled = true }
            .onDisappear { UIApplication.shared.isIdleTimerDisabled = false }
            .onKeyDown { event in
                guard let direction = Direction(rawValue: event.key.keyCode) else { return }
                squarePosition = moveSquare(direction: direction)
            }
    }

    private func moveSquare(direction: Direction) -> CGSize {
        let step: CGFloat = 10

        switch direction {
        case .up:
            return CGSize(width: squarePosition.width, height: squarePosition.height - step)
        case .down:
            return CGSize(width: squarePosition.width, height: squarePosition.height + step)
        case .left:
            return CGSize(width: squarePosition.width - step, height: squarePosition.height)
        case .right:
            return CGSize(width: squarePosition.width + step, height: squarePosition.height)
        }
    }
}

target_response:
The issue with the given code is that the `squarePosition` is not applied to the position of the rectangle. The `.position(x: 100, y: 100)` should be replaced with `.position(squarePosition)`. Additionally, the `Direction` enum should be configured with the correct key codes for arrow keys. Here's the updated code:

```swift
import SwiftUI

enum Direction: Int {
    case up = 126, down = 125, left = 123, right = 124
}

struct ContentView: View {
    @State private var squarePosition = CGSize(width: 100, height: 100)

    var body: some View {
        Rectangle()
            .fill(Color.blue)
            .frame(width: 100, height: 100)
            .position(squarePosition)
            .focusable()
            .onAppear { UIApplication.shared.isIdleTimerDisabled = true }
            .onDisappear { UIApplication.shared.isIdleTimerDisabled = false }
            .onKeyDown { event in
                guard let direction = Direction(rawValue: event.key.keyCode) else { return }
                squarePosition = moveSquare(direction: direction)
            }
    }

    private func moveSquare(direction: Direction) -> CGSize {
        let step: CGFloat = 10

        switch direction {
        case .up:
            return CGSize(width: squarePosition.width, height: squarePosition.height - step)
        case .down:
            return CGSize(width: squarePosition.width, height: squarePosition.height + step)
        case .left:
            return CGSize(width: squarePosition.width - step, height: squarePosition.height)
        case .right:
            return CGSize(width: squarePosition.width + step, height: squarePosition.height)
        }
    }
}
```

Now the `squarePosition` is correctly applied to the position of the rectangle, and it should work as expected. The `Direction` enum's raw values are also updated for arrow keys.

